de.Input.Width\" },\n    { \"From\": \"RowsProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"Flipbook\", \"ToSlot\": \"FlipbookNode.Input.Height\" },\n    { \"From\": \"MultiplyTimeSpeed\", \"FromSlot\": \"MultiplyNode.Output.Out\", \"To\": \"Flipbook\", \"ToSlot\": \"FlipbookNode.Input.Tile\" },\n\n    // 震动波 UV 偏移计算\n    { \"From\": \"UV\", \"FromSlot\": \"UVNode.Output.Out\", \"To\": \"SubtractCenter\", \"ToSlot\": \"SubtractNode.Input.A\" },\n    { \"From\": \"CenterVector\", \"FromSlot\": \"Vector2Node.Output.Out\", \"To\": \"SubtractCenter\", \"ToSlot\": \"SubtractNode.Input.B\" },\n    { \"From\": \"SubtractCenter\", \"FromSlot\": \"SubtractNode.Output.Out\", \"To\": \"Distance\", \"ToSlot\": \"LengthNode.Input.In\" },\n    { \"From\": \"SubtractCenter\", \"FromSlot\": \"SubtractNode.Output.Out\", \"To\": \"NormalizeOffset\", \"ToSlot\": \"NormalizeNode.Input.In\" },\n\n    { \"From\": \"Time\", \"FromSlot\": \"TimeNode.Output.Time\", \"To\": \"MultiplyTimeWaveSpeed\", \"ToSlot\": \"MultiplyNode.Input.A\" },\n    { \"From\": \"WaveSpeedProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"MultiplyTimeWaveSpeed\", \"ToSlot\": \"MultiplyNode.Input.B\" },\n\n    { \"From\": \"Distance\", \"FromSlot\": \"LengthNode.Output.Out\", \"To\": \"SubtractDistance\", \"ToSlot\": \"SubtractNode.Input.A\" },\n    { \"From\": \"MultiplyTimeWaveSpeed\", \"FromSlot\": \"MultiplyNode.Output.Out\", \"To\": \"SubtractDistance\", \"ToSlot\": \"SubtractNode.Input.B\" },\n\n    { \"From\": \"SubtractDistance\", \"FromSlot\": \"SubtractNode.Output.Out\", \"To\": \"MultiplyFrequency\", \"ToSlot\": \"MultiplyNode.Input.A\" },\n    { \"From\": \"WaveFreqProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"MultiplyFrequency\", \"ToSlot\": \"MultiplyNode.Input.B\" },\n\n    { \"From\": \"MultiplyFrequency\", \"FromSlot\": \"MultiplyNode.Output.Out\", \"To\": \"SineWave\", \"ToSlot\": \"SineNode.Input.In\" },\n    { \"From\": \"SineWave\", \"FromSlot\": \"SineNode.Output.Out\", \"To\": \"MultiplyStrength\", \"ToSlot\": \"MultiplyNode.Input.A\" },\n    { \"From\": \"WaveStrengthProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"MultiplyStrength\", \"ToSlot\": \"MultiplyNode.Input.B\" },\n\n    { \"From\": \"NormalizeOffset\", \"FromSlot\": \"NormalizeNode.Output.Out\", \"To\": \"MultiplyOffsetDirection\", \"ToSlot\": \"MultiplyNode.Input.A\" },\n    { \"From\": \"MultiplyStrength\", \"FromSlot\": \"MultiplyNode.Output.Out\", \"To\": \"MultiplyOffsetDirection\", \"ToSlot\": \"MultiplyNode.Input.B\" },\n\n    { \"From\": \"Flipbook\", \"FromSlot\": \"FlipbookNode.Output.Out\", \"To\": \"AddOffsetUV\", \"ToSlot\": \"AddNode.Input.A\" },\n    { \"From\": \"MultiplyOffsetDirection\", \"FromSlot\": \"MultiplyNode.Output.Out\", \"To\": \"AddOffsetUV\", \"ToSlot\": \"AddNode.Input.B\" },\n\n    // 采样纹理\n    { \"From\": \"AddOffsetUV\", \"FromSlot\": \"AddNode.Output.Out\", \"To\": \"SampleTexture\", \"ToSlot\": \"SampleTexture2DNode.Input.UV\" },\n    { \"From\": \"MainTexProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"SampleTexture\", \"ToSlot\": \"SampleTexture2DNode.Input.Texture\" },\n    { \"From\": \"SamplerState\", \"FromSlot\": \"SamplerStateNode.Output.Out\", \"To\": \"SampleTexture\", \"ToSlot\": \"SampleTexture2DNode.Input.Sampler\" },\n\n    // 基础颜色\n    { \"From\": \"SampleTexture\", \"FromSlot\": \"SampleTexture2DNode.Output.RGBA\", \"To\": \"MultiplyBaseColor\", \"ToSlot\": \"MultiplyNode.Input.A\" },\n    { \"From\": \"BaseColorProp\", \"FromSlot\": \"PropertyNode.Output.Out\", \"To\": \"MultiplyBaseColor\", \"ToSlot\": \"MultiplyNode.Input.B\" },\n\n    // 震动波 Emission 遮罩 (基于距离衰减，使波纹越远越淡)\n    { \"From\": \"Distance\", \"FromSlot\": \"LengthNode.Output.Out\", \"To\": \"OneMinusDistance\", \"ToSlot\": \"OneMinusNode.Input.In\" },\n    { \"From\": \"OneMinusDistance\", \"FromSlot\": \"OneMinusNode.Output.Out\", \"To\": \"SaturateWaveMask\", \"ToSlot\": \"SaturateNode.Input.In\" },\n\n    // 波纹值转为